# Express.js Application Architecture

## Recommended Folder Structure
```
src/
├── config/
│   ├── database.js
│   ├── passport.js
│   └── index.js
├── controllers/
│   ├── auth.controller.js
│   └── user.controller.js
├── middleware/
│   ├── auth.js
│   ├── validate.js
│   └── errorHandler.js
├── models/
│   ├── User.js
│   └── index.js
├── routes/
│   ├── auth.routes.js
│   ├── user.routes.js
│   └── index.js
├── services/
│   ├── auth.service.js
│   └── user.service.js
├── utils/
│   ├── ApiError.js
│   └── catchAsync.js
├── validations/
│   └── user.validation.js
├── app.js
└── server.js
```

## Key Principles
1. **Separation of Concerns**: Routes → Controllers → Services → Models
2. **Error Handling**: Centralized error handler middleware
3. **Validation**: Validate input at route level
4. **Async/Await**: Use catchAsync wrapper
5. **Environment Config**: Use dotenv

## Pattern Example
```javascript
// utils/catchAsync.js
const catchAsync = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// controllers/user.controller.js
const userService = require('../services/user.service');
const catchAsync = require('../utils/catchAsync');

exports.getUsers = catchAsync(async (req, res) => {
  const users = await userService.getUsers(req.query);
  res.json({ success: true, data: users });
});

// services/user.service.js
const User = require('../models/User');

exports.getUsers = async ({ page = 1, limit = 20 }) => {
  const skip = (page - 1) * limit;
  return User.find().skip(skip).limit(limit);
};

// routes/user.routes.js
const router = require('express').Router();
const { getUsers } = require('../controllers/user.controller');
const auth = require('../middleware/auth');

router.get('/', auth, getUsers);
module.exports = router;
```

# Express.js Debugging Guide

## Async Errors Not Caught

### Problem
Unhandled promise rejections crash the app.

### Solutions
```javascript
// BAD: Unhandled async error
app.get('/users', async (req, res) => {
  const users = await User.find();  // If throws, app crashes!
  res.json(users);
});

// GOOD: catchAsync wrapper
const catchAsync = fn => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

app.get('/users', catchAsync(async (req, res) => {
  const users = await User.find();
  res.json(users);
}));

// GOOD: express-async-errors package
require('express-async-errors');
// Now async errors auto-forward to error handler
```

## Middleware Order Issues

```javascript
// BAD: Error handler before routes
app.use(errorHandler);  // Too early!
app.use('/api', routes);

// GOOD: Correct order
app.use(express.json());           // 1. Body parser
app.use(cors());                    // 2. CORS
app.use('/api', routes);            // 3. Routes
app.use(notFoundHandler);           // 4. 404 handler
app.use(errorHandler);              // 5. Error handler (LAST)
```

## Memory Leaks

```javascript
// BAD: Event listeners accumulating
app.get('/stream', (req, res) => {
  const stream = getDataStream();
  stream.on('data', chunk => res.write(chunk));
  // Missing cleanup!
});

// GOOD: Clean up on connection close
app.get('/stream', (req, res) => {
  const stream = getDataStream();
  stream.pipe(res);

  req.on('close', () => {
    stream.destroy();
  });
});

// Debug memory
process.on('warning', e => console.warn(e.stack));
setInterval(() => {
  console.log('Memory:', process.memoryUsage().heapUsed / 1024 / 1024, 'MB');
}, 10000);
```

## MongoDB Connection Issues

```javascript
// Handle connection errors
mongoose.connect(MONGO_URI, {
  maxPoolSize: 10,
  serverSelectionTimeoutMS: 5000,
});

mongoose.connection.on('error', err => {
  console.error('MongoDB error:', err);
});

mongoose.connection.on('disconnected', () => {
  console.log('MongoDB disconnected, reconnecting...');
});
```
